import { strictEqual } from "assert";
import { describe, it } from "vitest";
import { renderEnumFile } from "../../src/codegen/enums/handlebars.js";
import type { EnumGroup } from "../../src/codegen/enums/render.js";

const LICENSE_HEADER =
  "# --------------------------------------------------------------------------\n" +
  "# Copyright (c) Microsoft Corporation. All rights reserved.\n" +
  "# Licensed under the MIT License. See License.txt in the project root for license information.\n" +
  "# Code generated by Microsoft (R) Python Code Generator.\n" +
  "# Changes may cause incorrect behavior and will be lost if the code is regenerated.\n" +
  "# --------------------------------------------------------------------------";

const colorAndPriority: EnumGroup = {
  namespace: "enumsample",
  enums: [
    {
      name: "Color",
      signature: "class Color(str, Enum, metaclass=CaseInsensitiveEnumMeta):",
      docstring: '"""The color of the thing.\n    """',
      values: [
        { assignment: 'RED = "red"', docstring: '"""the red one."""' },
        { assignment: 'GREEN = "green"', docstring: '"""GREEN."""' },
      ],
    },
    {
      name: "Priority",
      signature: "class Priority(int, Enum, metaclass=CaseInsensitiveEnumMeta):",
      docstring: '"""Type of Priority.\n    """',
      values: [
        { assignment: "LOW = 1", docstring: '"""low priority."""' },
        { assignment: "HIGH = 10", docstring: '"""HIGH."""' },
      ],
    },
  ],
};

describe("typespec-python: renderEnumFile", () => {
  it("renders the azure flavor header and enum classes", () => {
    const result = renderEnumFile(colorAndPriority, {
      licenseHeader: LICENSE_HEADER,
      coreImport: "azure.core",
    });
    const expected = [
      "# coding=utf-8",
      "# --------------------------------------------------------------------------",
      "# Copyright (c) Microsoft Corporation. All rights reserved.",
      "# Licensed under the MIT License. See License.txt in the project root for license information.",
      "# Code generated by Microsoft (R) Python Code Generator.",
      "# Changes may cause incorrect behavior and will be lost if the code is regenerated.",
      "# --------------------------------------------------------------------------",
      "",
      "from enum import Enum",
      "from azure.core import CaseInsensitiveEnumMeta",
      "",
      "",
      "class Color(str, Enum, metaclass=CaseInsensitiveEnumMeta):",
      '    """The color of the thing.',
      '    """',
      "",
      '    RED = "red"',
      '    """the red one."""',
      '    GREEN = "green"',
      '    """GREEN."""',
      "",
      "class Priority(int, Enum, metaclass=CaseInsensitiveEnumMeta):",
      '    """Type of Priority.',
      '    """',
      "",
      "    LOW = 1",
      '    """low priority."""',
      "    HIGH = 10",
      '    """HIGH."""',
      "",
    ].join("\n");
    strictEqual(result, expected);
  });

  it("renders the unbranded flavor without a license header", () => {
    const group: EnumGroup = {
      namespace: "enumsample",
      enums: [colorAndPriority.enums[0]],
    };
    const result = renderEnumFile(group, {
      licenseHeader: "",
      coreImport: "corehttp.utils",
    });
    const expected = [
      "# coding=utf-8",
      "",
      "from enum import Enum",
      "from corehttp.utils import CaseInsensitiveEnumMeta",
      "",
      "",
      "class Color(str, Enum, metaclass=CaseInsensitiveEnumMeta):",
      '    """The color of the thing.',
      '    """',
      "",
      '    RED = "red"',
      '    """the red one."""',
      '    GREEN = "green"',
      '    """GREEN."""',
      "",
    ].join("\n");
    strictEqual(result, expected);
  });

  it("renders a multi-line class signature for name-too-long enums", () => {
    const group: EnumGroup = {
      namespace: "enumsample",
      enums: [
        {
          name: "AVeryLongEnumNameThatExceedsTheNameLengthLimitForSure",
          signature:
            "class AVeryLongEnumNameThatExceedsTheNameLengthLimitForSure(  # pylint: disable=name-too-long\n" +
            "    str, Enum, metaclass=CaseInsensitiveEnumMeta\n):",
          docstring: '"""Type of AVeryLongEnumNameThatExceedsTheNameLengthLimitForSure.\n    """',
          values: [{ assignment: 'A = "a"', docstring: '"""A."""' }],
        },
      ],
    };
    const result = renderEnumFile(group, { licenseHeader: "", coreImport: "corehttp.utils" });
    strictEqual(
      result.includes(
        "class AVeryLongEnumNameThatExceedsTheNameLengthLimitForSure(  # pylint: disable=name-too-long\n" +
          "    str, Enum, metaclass=CaseInsensitiveEnumMeta\n):",
      ),
      true,
    );
  });
});
